def build_bst_from_string(s, root=None):
    if not s:
        return root
    char = s[0].lower()
    if root is None:
        root = {'val': char, 'left': None, 'right': None}
    elif char < root['val']:
        root['left'] = build_bst_from_string(s[1:], root['left'])
    elif char > root['val']:
        root['right'] = build_bst_from_string(s[1:], root['right'])
    else:
        root = build_bst_from_string(s[1:], root)
    return root

